SKILL = {'name': 'test_suite_validation', 'keywords': ['unit testing', 'assertions', 'error handling', 'input validation', 'division by zero', 'type checking'], 'prompt_fragment': 'Implementa y ejecuta una suite de pruebas que cubra casos válidos e inválidos con assertions. Cada función valida tipos numéricos y maneja errores con excepciones ValueError. Incluye casos de borde como división por cero. Usa bloques try/except para verificar que se lanzan excepciones correctas y mensajes exactos. Imprime resultado final solo si todos los tests pasan.', 'example_code': 'def suma(a, b):\n    if not isinstance(a, (int, float)) or not isinstance(b, (int, float)):\n        raise ValueError("Entradas no numéricas")\n    return a + b\n\ndef division(a, b):\n    if not isinstance(a, (int, float)) or not isinstance(b, (int, float)):\n        raise ValueError("Entradas no numéricas")\n    if b == 0:\n        raise ValueError("División por cero")\n    return a / b\n\n# Test suite\nassert suma(2, 3) == 5\nassert division(10, 2) == 5.0\ntry:\n    division(10, 0)\n    assert False\nexcept ValueError as e:\n    assert str(e) == "División por cero"\n\ntry:\n    division("z", 2)\n    assert False\nexcept ValueError as e:\n    assert str(e) == "Entradas no numéricas"\n\nprint("CRITERIO OK")'}
